const CARBON_VALUE_PER_TON = 180; // USD per ton of CO2 equivalent (reflects social cost of carbon, often debated, conservative average) 
const GREEN_SPACE_VALUE_PER_ACRE_ANNUAL = 6000; // USD per acre per year (ecosystem services, recreation, biodiversity, stormwater management) 
const COMMUNITY_ACCESS_VALUE_PER_SCORE_POINT_ANNUAL = 120000; // USD per score point per year (proxy for time savings, reduced congestion, improved connectivity, increased economic activity) 
const PUBLIC_HEALTH_VALUE_PER_SCORE_POINT_ANNUAL = 80000; // USD per score point per year (proxy for healthcare savings, improved well-being, productivity gains from better air/water quality, active living) 
const LOCAL_SPEND_MULTIPLIER = 1.7; // Economic multiplier for money recirculated locally (ranges 1.2 to 2.5 depending on region and industry, conservative average) 
const PROPERTY_VALUE_IMPACT_FACTOR = 0.8; // Factor applied to project_cost to estimate the total value of properties in the project's sphere of influence for calculation of increase (simplified proxy, assumes impact radius proportional to project scale) 

const projectCost = Number(inputs.project_cost) || 0; 
const projectDurationYears = Math.max(1, Number(inputs.project_duration_years) || 1); 
const directJobsCreated = Math.max(0, Number(inputs.direct_jobs_created) || 0); 
const avgAnnualWage = Math.max(0, Number(inputs.avg_annual_wage) || 0); 
const localSpendPercentage = Math.min(100, Math.max(0, Number(inputs.local_spend_percentage) || 0)); 
const carbonReductionTonsAnnually = Math.max(0, Number(inputs.carbon_reduction_tons_annually) || 0); 
const greenSpaceAcresAdded = Math.max(0, Number(inputs.green_space_acres_added) || 0); 
const communityAccessImprovementScore = Math.min(10, Math.max(1, Number(inputs.community_access_improvement_score) || 1)); 
const localPropertyValueIncreasePct = Math.min(50, Math.max(0, Number(inputs.local_property_value_increase_pct) || 0)); 
const publicHealthBenefitScore = Math.min(10, Math.max(1, Number(inputs.public_health_benefit_score) || 1)); 

// --- Calculation Steps --- 

// 1. Economic Impact 
// Value from direct jobs created over project duration 
const jobCreationValue = directJobsCreated * avgAnnualWage * projectDurationYears; 
// Value from local spending, considering multiplier effect (only the 'new' economic activity from recirculation) 
const localSpendingValue = (projectCost * (localSpendPercentage / 100)) * (LOCAL_SPEND_MULTIPLIER - 1); 
const economicImpactValue = jobCreationValue + localSpendingValue; 

// 2. Environmental Impact (annual values summed over project duration) 
const carbonReductionValueAnnual = carbonReductionTonsAnnually * CARBON_VALUE_PER_TON; 
const greenSpaceValueAnnual = greenSpaceAcresAdded * GREEN_SPACE_VALUE_PER_ACRE_ANNUAL; 
const environmentalImpactValue = (carbonReductionValueAnnual + greenSpaceValueAnnual) * projectDurationYears; 

// 3. Community Development Impact 
// Community Access Improvement: Annual benefit multiplied by duration 
const communityAccessValueAnnual = communityAccessImprovementScore * COMMUNITY_ACCESS_VALUE_PER_SCORE_POINT_ANNUAL; 
// Public Health Benefits: Annual benefit multiplied by duration 
const publicHealthValueAnnual = publicHealthBenefitScore * PUBLIC_HEALTH_VALUE_PER_SCORE_POINT_ANNUAL; 
// Property Value Increase: Simplified as a percentage of an estimated affected property value base derived from project cost. 
// This assumes the project itself stimulates property value increases in a surrounding area proportional to its scale. 
const affectedPropertyValueBase = projectCost * PROPERTY_VALUE_IMPACT_FACTOR; 
const propertyValueIncreaseValue = affectedPropertyValueBase * (localPropertyValueIncreasePct / 100); 

const communityDevelopmentValue = (communityAccessValueAnnual + publicHealthValueAnnual) * projectDurationYears + propertyValueIncreaseValue; 

// 4. Total Social Benefits 
const totalSocialBenefits = economicImpactValue + environmentalImpactValue + communityDevelopmentValue; 

// 5. Net Social ROI 
const netSocialROI = totalSocialBenefits - projectCost; 

// 6. Social ROI Ratio (as a percentage, handling division by zero) 
const socialROIRatio = projectCost > 0 ? (netSocialROI / projectCost) * 100 : 0; 

// Return the calculated outputs 
return { 
    total_project_cost: projectCost, 
    economic_impact_value: economicImpactValue, 
    environmental_impact_value: environmentalImpactValue, 
    community_development_value: communityDevelopmentValue, 
    total_social_benefits: totalSocialBenefits, 
    net_social_roi: netSocialROI, 
    social_roi_ratio: socialROIRatio 
};
